css:
.loader { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.loader-chrome {
  --red: #dd5144;
  --blue: #4285f4;
  --yellow: #ffcd46;
  --white: #e9e9e9;
  --green: #1da462;
  position: relative;
  width: 136px;
  height: 136px;
  background-color: var(--red);
  border-radius: 50%;
  overflow: hidden;
  animation: animacion 5s linear infinite;
}

.circle-blue-center {
width: 72px;
height: 72px;
background-color: var(--blue);
position: relative;
border-radius: inherit;
border: 8px solid var(--white);
z-index: 3;
}

.yellow-right {
position: absolute;
background-color: var(--yellow);
width: 100%;
height: 100%;
top: 38%;
left: 54%;
transform: skewX(-30deg);
z-index: 2;
}

.yellow-right::before {
content: "";
display: block;
width: 100%;
height: 100%;
position: absolute;
top: -20px;
left: 20%;
background-color: inherit;
transform: skewX(50deg);
z-index: 2;
}

.green-left {
position: absolute;
left: -84px;
top: 38px;
background-color: var(--green);
width: 100%;
height: 100%;
transform: skewX(35deg);
z-index: 1;
}

.green-left::before {
content: "";
display: block;
width: 100%;
position: absolute;
height: 100%;
z-index: 1;
top: 52px;
left: 38px;
background-color: inherit;
transform: skewX(0deg);
}

@keyframes animacion {
0% {
transform: scale(0.9) rotate(0deg);
opacity: 0.65;
}

35%,
75% {
transform: scale(1) rotate(720deg);
opacity: 1;
}

100% {
transform: scale(0.9) rotate(1080deg);
opacity: 0.65;
}
}
